#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        int hasI=0, hasY=0;
        for(int i=0;i<N;i++){
            if(s[i]=='I') hasI=1;
            else if(s[i]=='Y') hasY=1;
        }
        if(hasI) printf("INDIAN\n");
        else if(hasY) printf("NOT INDIAN\n");
        else printf("NOT SURE\n");
    }
    return 0;
}

