import sys

def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        if 'I' in s:
            out_lines.append('INDIAN')
        elif 'Y' in s:
            out_lines.append('NOT INDIAN')
        else:
            out_lines.append('NOT SURE')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

